import{_ as e,o as a,c as i,a7 as r}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Covenants List","description":"","frontmatter":{},"headers":[],"relativePath":"en/covenants/list.md","filePath":"en/covenants/list.md","lastUpdated":1775394001000}'),d={name:"en/covenants/list.md"};function s(n,t,o,l,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="covenants-list" tabindex="-1">Covenants List <a class="header-anchor" href="#covenants-list" aria-label="Permalink to &quot;Covenants List&quot;">​</a></h1><p>A complete list of all 17 Covenant sets in Morimens. Covenants unlock at account level 35. Each set has 6 pieces, providing 3-piece and 6-piece set bonuses.</p><h2 id="covenant-sets" tabindex="-1">Covenant Sets <a class="header-anchor" href="#covenant-sets" aria-label="Permalink to &quot;Covenant Sets&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Covenant Name</th><th>Role</th><th>Effect</th><th>Source</th></tr></thead><tbody><tr><td><a href="./scarlet-palpitation.html">Scarlet Palpitation</a></td><td>DPS (Main Carry)</td><td>Provides dual crit (Crit Rate + Crit DMG). Universal set for all main carries -- suits 24, Lotan, Uvhash, etc.</td><td>Shop Exchange / Investigation Exchange / Phase Exchange</td></tr><tr><td><a href="./scarlet-embrace.html">Scarlet Embrace</a></td><td>Support / Sub-DPS</td><td>Suited for support characters who actively play cards. Effect is wasted if the wearer does not play cards.</td><td>Sediment Exchange</td></tr><tr><td><a href="./twisted-twins-black.html">Twisted Twins Black</a></td><td>DPS / Support</td><td>Copies the wearer&#39;s Strike card and adds it to the deck. Suits Lotan, Aigis.</td><td>Stage Drop</td></tr><tr><td><a href="./twisted-twins-white.html">Twisted Twins White</a></td><td>Tank / Defense</td><td>Copies the wearer&#39;s Defense card and adds it to the deck. Suits Ogier, Nodera.</td><td>Stage Drop</td></tr><tr><td><a href="./steppe-wolf.html">Steppe Wolf</a></td><td>DPS / Poison</td><td>DMG Amplification + counter/poison bonus. Suits Liz, Wanda. v1.4.4: 6-piece no longer requires specific attribute.</td><td>Rose Scrip Shop</td></tr><tr><td><a href="./deus-ex-machina.html">Deus Ex Machina</a></td><td>Support</td><td>AP/Arithmetica related effects. Support character exclusive.</td><td>Stage Drop</td></tr><tr><td><a href="./returnal-line.html">Returnal Line</a></td><td>Deep Sea DPS</td><td>Power bonus or additional tentacle attack count. Deep Sea character exclusive.</td><td>Stage Drop</td></tr><tr><td><a href="./burial-ground-whispers.html">Burial Ground Whispers</a></td><td>Survival / Utility</td><td>6-piece: +25% Death Resist at stage start; gain 50 Aliemus after triggering Death Resist.</td><td>Stage Drop</td></tr><tr><td><a href="./curse-rabbit.html">Curse Rabbit</a></td><td>Healer</td><td>Heal + shield bonus. Suits Salvador, Doll, Celeste. v1.4.4: 6-piece no longer requires specific attribute.</td><td>Deep Dive Shop</td></tr><tr><td><a href="./distant-feast.html">Distant Feast</a></td><td>Tank / Defense</td><td>Large defense bonuses. Nodera post-awakening can provide 200+ shield per defense card. v1.4.4: 6-piece no longer requires specific attribute.</td><td>Lightless Shop</td></tr><tr><td><a href="./unstained-chronicle.html">Unstained Chronicle</a></td><td>Support</td><td>Support-type character exclusive set.</td><td>—</td></tr><tr><td><a href="./organic-form.html">Organic Form</a></td><td>Utility</td><td>6-piece (team-unique): At exploration start, deduct up to 100% Death Resist; per 1% deducted, wearer&#39;s Aliemus DMG +0.15%.</td><td>—</td></tr><tr><td><a href="./antinomy.html">Antinomy</a></td><td>DPS</td><td>6-piece (team-unique): Aliemus cap and Overload cost +20; command card crit rate, crit DMG, shield, heal +20%.</td><td>—</td></tr><tr><td><a href="./dream-of-medication.html">Dream of Medication</a></td><td>Support</td><td>6-piece (team-unique): Black Ink gain -8 at battle end; at battle start, add original versions of wearer&#39;s non-strike/non-defense cards to draw pile (max 1 per type).</td><td>—</td></tr><tr><td><a href="./ring-of-36-chambers.html">Ring of 36 Chambers</a></td><td>DPS</td><td>6-piece (team-unique): Silver Key cap and skill cost +200; Overload crit rate, crit DMG, shield, heal +30%.</td><td>—</td></tr><tr><td><a href="./further-metamorphosis.html">Further Metamorphosis</a></td><td>—</td><td>Covenant set mentioned in English strategy guides.</td><td>—</td></tr><tr><td><a href="./apocalypse.html">Apocalypse</a></td><td>Endgame</td><td>Endgame content covenant set.</td><td>—</td></tr></tbody></table><h2 id="main-stat-options" tabindex="-1">Main Stat Options <a class="header-anchor" href="#main-stat-options" aria-label="Permalink to &quot;Main Stat Options&quot;">​</a></h2><p>Covenant pieces can roll the following main stats:</p><ul><li>Crit Rate</li><li>Crit DMG</li><li>DMG Amplification</li><li>Keyflare Regen (Silver Key)</li><li>Aliemus Regen</li><li>Realm Mastery</li><li>Death Resist</li><li>Black Ink Drop</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Covenants can be equipped by any Awakener. Focus on farming Covenants with stats that match your main team&#39;s needs. Covenant transcription costs 3 Thousand-Face Seals + 7,500 Rose Scrip per attempt.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Covenants Overview</a></li><li><a href="./../wheels/list.html">Wheels of Destiny List</a></li><li><a href="./../modes/smelting.html">Smelting Room</a></li></ul>',10)])])}const m=e(d,[["render",s]]);export{u as __pageData,m as default};
